def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(1, 7):
                for b in range(1, a+4):
                    value = np.sin(a * ratio) * np.exp(-b / (ratio + 0.5)) * ((ratio - 7) ** 4) / (a * b + 1)
                    priority += value * np.cos(i * (a + b) * 0.5)
            priority += np.tanh(ratio - 8) * 20
            if i % 2 == 1:
                priority += np.log1p(bin_cap) * np.sin(ratio * i)
            else:
                priority -= np.sqrt(bin_cap) * np.cos(ratio * i * 1.3)
        elif 5 < ratio <= 8:
            s = 0
            for x in range(1, 10):
                s += ((ratio - 5) ** x) / (x * x + 1) * np.sin(x * ratio * 1.7)
                if x % 3 == 0:
                    s += np.cos(bin_cap * x / (item + 1))
            priority = s * np.tanh(ratio - 6) + np.log(ratio) * 8
            for y in range(1, 5):
                priority += np.sign(np.sin(ratio * y)) * (y / (ratio + 1.2)) * (bin_cap ** 0.3)
        elif 2 < ratio <= 5:
            s = 0
            for p in range(2, 15):
                factor = ((5 - ratio) ** p) / (np.sqrt(p) + 1)
                s += factor * np.cos(p * ratio / 2)
                if (p+i) % 2 == 0:
                    s += np.sin(p * item / (bin_cap + 1))
            priority = s * 5 - np.log(ratio + 1) * 10 + np.tanh(3 * ratio) * 4
            if bin_cap < item:
                priority += np.exp(-ratio) * 10
        elif 1 < ratio <= 2:
            s1 = 0
            for u in range(1, 12):
                s1 += ((ratio - 1) ** u) / (u + 2) * np.sin(u * ratio * 3)
            s2 = 0
            for v in range(1, 8):
                s2 += ((2 - ratio) ** v) / (v * 2.5) * np.cos(v * item * 1.5)
            priority = s1 - s2 + np.sqrt(bin_cap) * 2
            if i % 4 == 0:
                priority += np.log1p(item * bin_cap) * 3
        elif 0.5 <= ratio < 1:
            s = 0
            for m in range(1, 20):
                term = ((1 - ratio) ** m) / (m ** 1.5 + 1) * np.cos(m * ratio * 4)
                s += term
            penalty = 0
            if bin_cap < item * 0.7:
                penalty += np.exp(-bin_cap / item) * 5
            else:
                penalty -= np.sin(bin_cap - item) * 3
            priority = s + penalty + np.tanh(ratio) * 7
            for n in range(1, 6):
                if (i + n) % 5 == 0:
                    priority += np.sin(n * ratio * i) * (ratio ** n)
                else:
                    priority -= np.cos(n * ratio * i) / (n + 1)
        elif 0.2 <= ratio < 0.5:
            s = 0
            for q in range(1, 25):
                s += ((0.5 - ratio) ** q) / (q + 1) * np.tanh(q * item / (bin_cap + 2))
            priority = s / (np.sqrt(bin_cap + 1)) * 4
            for w in range(1, 5):
                multiplier = np.sin(w * ratio * 2.5) if (i + w) % 3 == 0 else np.cos(w * ratio * 2.5)
                priority += multiplier * np.log1p(item * w)
            if bin_cap < item * 0.3:
                priority += np.exp(-ratio) * 7
            else:
                priority -= np.tanh(bin_cap / (item + 1)) * 5
        elif 0.05 <= ratio < 0.2:
            s = 0
            for z in range(1, 30):
                s += ((0.2 - ratio) ** z) / (z ** 2 + 2) * np.cos(z * ratio * 5)
                if z % 2 == 0:
                    s += np.sin(z * bin_cap / (item + 1.5))
            priority = s + 10 / (bin_cap + 1)
            if (int(item * 1000) + i) % 7 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 8
            else:
                priority -= np.exp(-ratio * 3) * 6
        else:
            s = 0
            for aa in range(1, 15):
                s += ((0.05 - ratio) ** aa) / (aa + 3) * np.sin(aa * item * 0.7)
                if aa % 4 == 0:
                    s += np.cos(aa * bin_cap / (item + 0.8))
            priority = s + 5 / (bin_cap + 0.5)
            if (int(item * 500) + i) % 9 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.05:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 4) * 7
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 5 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
